import React, { useState, useEffect, useCallback } from 'react';
import Section from './Section';
import { PRODUCTS, BRAND, WHATSAPP_MESSAGES } from '../constants';
import Button from './Button';
import { MessageCircle, ChevronLeft, ChevronRight } from 'lucide-react';

const Products: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [itemsPerPage, setItemsPerPage] = useState(1);

  // Ajusta o número de itens visíveis baseado na largura da tela
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth >= 1024) {
        setItemsPerPage(3);
      } else if (window.innerWidth >= 768) {
        setItemsPerPage(2);
      } else {
        setItemsPerPage(1);
      }
    };

    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Calcula o índice máximo possível para não deixar espaço em branco no final
  const maxIndex = Math.max(0, PRODUCTS.length - itemsPerPage);

  const nextSlide = useCallback(() => {
    setCurrentIndex((prev) => (prev >= maxIndex ? 0 : prev + 1));
  }, [maxIndex]);

  const prevSlide = () => {
    setCurrentIndex((prev) => (prev === 0 ? maxIndex : prev - 1));
  };

  // Autoplay (Rotação automática)
  useEffect(() => {
    const timer = setInterval(() => {
      nextSlide();
    }, 4000); // Gira a cada 4 segundos

    return () => clearInterval(timer);
  }, [nextSlide]);

  const handleProductClick = () => {
    const url = `https://wa.me/${BRAND.whatsapp}?text=${encodeURIComponent(WHATSAPP_MESSAGES.product)}`;
    window.open(url, '_blank');
  };

  return (
    <Section id="sabores" darker>
      <div className="text-center mb-12">
        <span className="text-brand-gold font-bold tracking-widest text-sm uppercase mb-2 block">Nossos Destaques</span>
        <h2 className="font-serif text-3xl md:text-5xl font-bold text-brand-cream">
          Sabores Irresistíveis
        </h2>
      </div>

      {/* Container do Carrossel */}
      <div className="relative max-w-6xl mx-auto px-4 mb-12 group">

        {/* Botão Anterior */}
        <button 
          onClick={prevSlide}
          className="absolute left-0 top-1/2 -translate-y-1/2 -translate-x-2 md:-translate-x-6 z-20 bg-brand-gold text-brand-dark p-2 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity disabled:opacity-30 hover:bg-white"
          aria-label="Anterior"
        >
          <ChevronLeft size={24} />
        </button>

        {/* Janela de Visualização */}
        <div className="overflow-hidden rounded-xl">
          <div 
            className="flex transition-transform duration-500 ease-out"
            style={{ transform: `translateX(-${currentIndex * (100 / itemsPerPage)}%)` }}
          >
            {PRODUCTS.map((product) => (
              <div 
                key={product.id} 
                className="flex-shrink-0 px-3"
                style={{ width: `${100 / itemsPerPage}%` }}
              >
                <div className="bg-brand-primary rounded-xl overflow-hidden shadow-lg border border-white/5 hover:border-brand-gold/30 transition-all h-full flex flex-col">
                  <div className="relative h-64 overflow-hidden">
                    <img 
                      src={product.image} 
                      alt={product.name} 
                      className="w-full h-full object-cover transition-transform duration-500 hover:scale-110"
                    />
                    <div className="absolute inset-0 bg-black/20 hover:bg-black/10 transition-colors"></div>
                  </div>
                  <div className="p-6 flex-grow flex flex-col justify-between">
                    <div>
                      <h3 className="text-xl font-bold text-brand-cream mb-2">{product.name}</h3>
                      <p className="text-stone-400 text-sm mb-4">{product.description}</p>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Botão Próximo */}
        <button 
          onClick={nextSlide}
          className="absolute right-0 top-1/2 -translate-y-1/2 translate-x-2 md:translate-x-6 z-20 bg-brand-gold text-brand-dark p-2 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity hover:bg-white"
          aria-label="Próximo"
        >
          <ChevronRight size={24} />
        </button>

        {/* Indicadores (Bolinhas) */}
        <div className="flex justify-center gap-2 mt-6">
          {Array.from({ length: maxIndex + 1 }).map((_, idx) => (
            <button
              key={idx}
              onClick={() => setCurrentIndex(idx)}
              className={`w-2.5 h-2.5 rounded-full transition-all ${
                currentIndex === idx ? 'bg-brand-gold w-6' : 'bg-stone-600 hover:bg-stone-500'
              }`}
              aria-label={`Ir para slide ${idx + 1}`}
            />
          ))}
        </div>
      </div>

      <div className="bg-brand-gold/10 border border-brand-gold/20 rounded-lg p-6 text-center max-w-2xl mx-auto">
        <p className="text-brand-cream mb-4">
          <span className="text-brand-gold font-bold">Nota:</span> Consulte disponibilidade, tamanhos e edições especiais no nosso catálogo completo.
        </p>
        <Button onClick={handleProductClick} variant="outline" className="!px-8 !py-2">
          <MessageCircle className="w-4 h-4 mr-2"/>
          Solicitar Catálogo Completo
        </Button>
      </div>
    </Section>
  );
};

export default Products;

